external_knowledge:
- 'commenting voices' refers to the number of comments a user and their followers have made; 
- 'leader' refers to a user with a specific 'user_id'; 
- 'entourage' refers to the users being followed by the leader, identified by 'followee_id' in the 'user_follows' table where 'follower_id' is the leader's 'user_id'.

sql:
SELECT COUNT(comment_id) 
FROM comments 
WHERE author_id IN (
  SELECT DISTINCT user_id 
  FROM comment_likes
);

SELECT * 
FROM post_views 
WHERE user_id = 0 AND post_id = 1;

SELECT 
  (SELECT COUNT(*) FROM comment_likes) AS total_likes,
  (SELECT COUNT(*) FROM comment_replies) AS total_replies;

SELECT COUNT(comment_id)
FROM comment_history
WHERE is_reverted = 1;

SELECT COUNT(DISTINCT comment_id) 
FROM comments 
WHERE post_id BETWEEN 1 AND 10;

SELECT COUNT(*) AS total_likes
FROM comment_likes
WHERE date(created_at) = '2018-08-02';

SELECT COUNT(comment_id) AS total_comments
FROM comments
WHERE author_id = 1 AND post_id = 1 AND status = 'approved';
